import { db } from "./firebase";
import { ref, push, set, get, child, update } from "firebase/database";
import { Budget } from "@/types";

const COLLECTION_NAME = "budgets";

export const createBudget = async (budget: Omit<Budget, 'id' | 'createdAt'>) => {
    try {
        const budgetsRef = ref(db, COLLECTION_NAME);
        const newBudgetRef = push(budgetsRef);

        await set(newBudgetRef, {
            ...budget,
            createdAt: new Date().toISOString()
        });

        return newBudgetRef.key;
    } catch (error) {
        console.error("Error creating budget: ", error);
        throw error;
    }
};

export const getBudgets = async (): Promise<Budget[]> => {
    try {
        const dbRef = ref(db);
        const snapshot = await get(child(dbRef, COLLECTION_NAME));

        if (snapshot.exists()) {
            const data = snapshot.val();
            return Object.entries(data).map(([key, v]: [string, any]) => ({
                id: key,
                ...v,
                createdAt: new Date(v.createdAt),
            })) as Budget[];
        }
        return [];
    } catch (error) {
        console.error("Error fetching budgets", error);
        return [];
    }
};

export const updateBudget = async (id: string, budget: Partial<Budget>) => {
    try {
        const budgetRef = ref(db, `${COLLECTION_NAME}/${id}`);
        await update(budgetRef, budget);
    } catch (error) {
        console.error("Error updating budget:", error);
        throw error;
    }
};
